		[OverloadResolutionPriority(1)]
		public static unsafe winmdroot.Foundation.HRESULT CreatePseudoConsole(winmdroot.System.Console.COORD size, SafeHandle hInput, SafeHandle hOutput, uint dwFlags, out global::Windows.Win32.ClosePseudoConsoleSafeHandle phPC)
		{
			bool hInputAddRef = false;
			bool hOutputAddRef = false;
			try
			{
				winmdroot.Foundation.HANDLE hInputLocal;
				if (hInput is object)
				{
					hInput.DangerousAddRef(ref hInputAddRef);
					hInputLocal = (winmdroot.Foundation.HANDLE)hInput.DangerousGetHandle();
				}
				else
					throw new ArgumentNullException(nameof(hInput));
				winmdroot.Foundation.HANDLE hOutputLocal;
				if (hOutput is object)
				{
					hOutput.DangerousAddRef(ref hOutputAddRef);
					hOutputLocal = (winmdroot.Foundation.HANDLE)hOutput.DangerousGetHandle();
				}
				else
					throw new ArgumentNullException(nameof(hOutput));
				winmdroot.System.Console.HPCON phPCLocal;
				phPC = new global::Windows.Win32.ClosePseudoConsoleSafeHandle(default, ownsHandle: true);
				winmdroot.Foundation.HRESULT __result = PInvoke.CreatePseudoConsole(size, hInputLocal, hOutputLocal, dwFlags, &phPCLocal);
				global::System.Runtime.InteropServices.Marshal.InitHandle(phPC, phPCLocal);
				return __result;
			}
			finally
			{
				if (hInputAddRef)
					hInput.DangerousRelease();
				if (hOutputAddRef)
					hOutput.DangerousRelease();
			}
		}

		/// <summary>See reference information about the CreatePseudoConsole function, which allocates a new pseudoconsole for the calling process.</summary>
		/// <param name="size">The dimensions of the window/buffer in count of characters that will be used on initial creation of the pseudoconsole. This can be adjusted later with [ResizePseudoConsole](resizepseudoconsole.md).</param>
