		[SupportedOSPlatform("windows5.1.2600")]
		public static partial winmdroot.Foundation.BOOL DebugActiveProcessStop(uint dwProcessId);

		/// <inheritdoc cref="CheckRemoteDebuggerPresent(winmdroot.Foundation.HANDLE, winmdroot.Foundation.BOOL*)"/>
		[SupportedOSPlatform("windows6.0.6000")]
		[OverloadResolutionPriority(1)]
		public static unsafe winmdroot.Foundation.BOOL CheckRemoteDebuggerPresent(SafeHandle hProcess, out winmdroot.Foundation.BOOL pbDebuggerPresent)
		{
			bool hProcessAddRef = false;
			try
			{
				fixed (winmdroot.Foundation.BOOL* pbDebuggerPresentLocal = &pbDebuggerPresent)
				{
					winmdroot.Foundation.HANDLE hProcessLocal;
					if (hProcess is object)
					{
						hProcess.DangerousAddRef(ref hProcessAddRef);
						hProcessLocal = (winmdroot.Foundation.HANDLE)hProcess.DangerousGetHandle();
					}
					else
						throw new ArgumentNullException(nameof(hProcess));
					winmdroot.Foundation.BOOL __result = PInvoke.CheckRemoteDebuggerPresent(hProcessLocal, pbDebuggerPresentLocal);
					return __result;
				}
			}
			finally
			{
				if (hProcessAddRef)
					hProcess.DangerousRelease();
			}
		}

