		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winbase/nf-winbase-getenabledxstatefeatures#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll"),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows6.1")]
		public static partial ulong GetEnabledXStateFeatures();

