		/// <summary>Terminates all processes currently associated with the job.</summary>
		/// <param name="hJob">
		/// <para>A handle to the job whose processes will be terminated. The <a href="https://docs.microsoft.com/windows/desktop/api/winbase/nf-winbase-createjobobjecta">CreateJobObject</a> or <a href="https://docs.microsoft.com/windows/desktop/api/winbase/nf-winbase-openjobobjecta">OpenJobObject</a> function returns this handle. This handle must have the JOB_OBJECT_TERMINATE access right. For more information, see <a href="https://docs.microsoft.com/windows/desktop/ProcThread/job-object-security-and-access-rights">Job Object Security and Access Rights</a>. The handle for each process in the job object must have the PROCESS_TERMINATE access right. For more information, see <a href="https://docs.microsoft.com/windows/desktop/ProcThread/process-security-and-access-rights">Process Security and Access Rights</a>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/jobapi2/nf-jobapi2-terminatejobobject#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="uExitCode">
		/// <para>The exit code to be used by all processes and threads in the job object. Use the <a href="https://docs.microsoft.com/windows/desktop/api/processthreadsapi/nf-processthreadsapi-getexitcodeprocess">GetExitCodeProcess</a> function to retrieve each process's exit value. Use the <a href="https://docs.microsoft.com/windows/desktop/api/processthreadsapi/nf-processthreadsapi-getexitcodethread">GetExitCodeThread</a> function to retrieve each thread's exit value.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/jobapi2/nf-jobapi2-terminatejobobject#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <returns>
		/// <para>If the function succeeds, the return value is nonzero. If the function fails, the return value is zero. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>.</para>
		/// </returns>
		/// <remarks>
		/// <para>It is not possible for any of the processes associated with the job to postpone or handle the termination. It is as if <a href="https://docs.microsoft.com/windows/desktop/api/processthreadsapi/nf-processthreadsapi-terminateprocess">TerminateProcess</a> were called for each process associated with the job. Terminating a nested job additionally terminates all child job objects. Resources used by the terminated jobs are charged up the parent job chain in the hierarchy. To compile an application that uses this function, define _WIN32_WINNT as 0x0500 or later. For more information, see <a href="https://docs.microsoft.com/windows/desktop/WinProg/using-the-windows-headers">Using the Windows Headers</a>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/jobapi2/nf-jobapi2-terminatejobobject#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.1.2600")]
		public static partial winmdroot.Foundation.BOOL TerminateJobObject(winmdroot.Foundation.HANDLE hJob, uint uExitCode);

