		[SupportedOSPlatform("windows6.1")]
		public static partial winmdroot.Foundation.BOOL PowerSetRequest(winmdroot.Foundation.HANDLE PowerRequest, winmdroot.System.Power.POWER_REQUEST_TYPE RequestType);

