		/// <summary>Decrements the reference count of a global string atom. If the atom's reference count reaches zero, GlobalDeleteAtom removes the string associated with the atom from the global atom table.</summary>
		/// <param name="nAtom">
		/// <para>Type: <b>ATOM</b> The atom and character string to be deleted.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winbase/nf-winbase-globaldeleteatom#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <returns>
		/// <para>Type: <b>ATOM</b> The function always returns (<b>ATOM</b>) 0. To determine whether the function has failed, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-setlasterror">SetLastError</a> with <b>ERROR_SUCCESS</b> before calling <b>GlobalDeleteAtom</b>, then call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>. If the last error code is still <b>ERROR_SUCCESS</b>, <b>GlobalDeleteAtom</b> has succeeded.</para>
		/// </returns>
		/// <remarks>
		/// <para>A string atom's reference count specifies the number of times the string has been added to the atom table. The <a href="https://docs.microsoft.com/windows/desktop/api/winbase/nf-winbase-globaladdatoma">GlobalAddAtom</a> function increments the reference count of a string that already exists in the global atom table each time it is called. Each call to <a href="https://docs.microsoft.com/windows/desktop/api/winbase/nf-winbase-globaladdatoma">GlobalAddAtom</a> should have a corresponding call to <b>GlobalDeleteAtom</b>. Do not call <b>GlobalDeleteAtom</b> more times than you call <b>GlobalAddAtom</b>, or you may delete the atom while other clients are using it. Applications using Dynamic Data Exchange (DDE) should follow the rules on global atom management to prevent leaks and premature deletion. <b>GlobalDeleteAtom</b> has no effect on an integer atom (an atom whose value is in the range 0x0001 to 0xBFFF). The function always returns zero for an integer atom.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winbase/nf-winbase-globaldeleteatom#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.0")]
		public static partial ushort GlobalDeleteAtom(ushort nAtom);

		/// <summary>Initializes the local atom table and sets the number of hash buckets to the specified size.</summary>
		/// <param name="nSize">
		/// <para>Type: <b>DWORD</b> The number of hash buckets to use for the atom table. If this parameter is zero, the default number of hash buckets are created. To achieve better performance, specify a prime number in <i>nSize</i>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winbase/nf-winbase-initatomtable#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <returns>
		/// <para>Type: <b>BOOL</b> If the function succeeds, the return value is nonzero. If the function fails, the return value is zero.</para>
		/// </returns>
		/// <remarks>
		/// <para>An application need not use this function to use a local atom table. The default number of hash buckets used is 37. If an application does use <b>InitAtomTable</b>, however, it should call the function before any other atom-management function. If an application uses a large number of local atoms, it can reduce the time required to add an atom to the local atom table or to find an atom in the table by increasing the size of the table. However, this increases the amount of memory required to maintain the table. The number of buckets in the global atom table cannot be changed. If the atom table has already been initialized, either explicitly by a prior call to <b>InitAtomTable</b>, or implicitly by the use of any atom-management function, <b>InitAtomTable</b> returns success without changing the number of hash buckets.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winbase/nf-winbase-initatomtable#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll"),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.0")]
		public static partial winmdroot.Foundation.BOOL InitAtomTable(uint nSize);

		/// <summary>Decrements the reference count of a local string atom. If the atom's reference count is reduced to zero, DeleteAtom removes the string associated with the atom from the local atom table.</summary>
		/// <param name="nAtom">
