		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winbase/nf-winbase-addatomw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <returns>
		/// <para>Type: <b>ATOM</b> If the function succeeds, the return value is the newly created atom. If the function fails, the return value is zero. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>.</para>
		/// </returns>
