		/// <para><see href="https://learn.microsoft.com/windows/win32/api/libloaderapi/nf-libloaderapi-enumresourcenamesw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="lParam">
		/// <para>Type: **LONG_PTR** An application-defined value passed to the callback function. This parameter can be used in error checking.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/libloaderapi/nf-libloaderapi-enumresourcenamesw#parameters">Read more on learn.microsoft.com</see>.</para>
