		/// </param>
		/// <param name="HeapInformationClass">
		/// <para>The class of information to be retrieved. This parameter can be the following value from the <b>HEAP_INFORMATION_CLASS</b> enumeration type. </para>
		/// <para>This doc was truncated.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/heapapi/nf-heapapi-heapqueryinformation#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="HeapInformation">A pointer to a buffer that receives the heap information. The format of this data depends on the value of the <i>HeapInformationClass</i> parameter.</param>
		/// <param name="HeapInformationLength">The size of the heap information being queried, in bytes.</param>
		/// <param name="ReturnLength">
		/// <para>A pointer to a variable that receives the length of data written to the <i>HeapInformation</i> buffer. If the buffer is too small, the function fails and <i>ReturnLength</i> specifies the minimum size required for the buffer.</para>
		/// <para>If you do not want to receive this information, specify <b>NULL</b>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/heapapi/nf-heapapi-heapqueryinformation#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <returns>
		/// <para>If the function succeeds, the return value is nonzero. If the function fails, the return value is zero. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>.</para>
		/// </returns>
		/// <remarks>
		/// <para>To enable the LFH or the terminate-on-corruption feature, use the <a href="https://docs.microsoft.com/windows/desktop/api/heapapi/nf-heapapi-heapsetinformation">HeapSetInformation</a> function. <b>Windows XP and Windows Server 2003:  </b> A look-aside list is a fast memory allocation mechanism that contains only fixed-sized blocks. Look-aside lists are enabled by default for heaps that support them. Starting with Windows Vista, look-aside lists are not used and the LFH is enabled by default. Look-aside lists are faster than general pool allocations that vary in size, because the system does not search for free memory that fits the allocation. In addition, access to look-aside lists is generally synchronized using fast atomic processor exchange instructions instead of mutexes or spinlocks. Look-aside lists can be created by the system or drivers. They can be allocated from paged or nonpaged pool.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/heapapi/nf-heapapi-heapqueryinformation#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.1.2600")]
		public static unsafe partial winmdroot.Foundation.BOOL HeapQueryInformation([Optional] winmdroot.Foundation.HANDLE HeapHandle, winmdroot.System.Memory.HEAP_INFORMATION_CLASS HeapInformationClass, [Optional] void* HeapInformation, nuint HeapInformationLength, [Optional] nuint* ReturnLength);

		/// <summary>Reserves, commits, or changes the state of a region of pages in the virtual address space of the calling process. (VirtualAlloc)</summary>
		/// <param name="lpAddress">
		/// <para>The starting address of the region to allocate. If the memory is being reserved, the specified address is rounded down to the nearest multiple of the allocation granularity. If the memory is already reserved and is being committed, the address is rounded down to the next page boundary. To determine the size of a page and the allocation granularity on the host computer, use the [GetSystemInfo](/windows/win32/api/sysinfoapi/nf-sysinfoapi-getsysteminfo) function. If this parameter is **NULL**, the system determines where to allocate the region. If this address is within an enclave that you have not initialized by calling [InitializeEnclave](/windows/win32/api/enclaveapi/nf-enclaveapi-initializeenclave), **VirtualAlloc** allocates a page of zeros for the enclave at that address. The page must be previously uncommitted, and will not be measured with the EEXTEND instruction of the Intel Software Guard Extensions programming model. If the address is within an enclave that you initialized, then the allocation operation fails with the **ERROR_INVALID_ADDRESS** error. That is true for enclaves that do not support dynamic memory management (i.e. SGX1). SGX2 enclaves will permit allocation, and the page must be accepted by the enclave after it has been allocated.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-virtualalloc#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="dwSize">The size of the region, in bytes. If the _lpAddress_ parameter is **NULL**, this value is rounded up to the next page boundary. Otherwise, the allocated pages include all pages containing one or more bytes in the range from _lpAddress_ to _lpAddress_+_dwSize_. This means that a 2-byte range straddling a page boundary causes both pages to be included in the allocated region.</param>
		/// <param name="flAllocationType"></param>
		/// <param name="flProtect">The memory protection for the region of pages to be allocated. If the pages are being committed, you can specify any one of the [memory protection constants](/windows/win32/Memory/memory-protection-constants).</param>
		/// <returns>
		/// <para>If the function succeeds, the return value is the base address of the allocated region of pages. If the function fails, the return value is **NULL**. To get extended error information, call [GetLastError](/windows/win32/api/errhandlingapi/nf-errhandlingapi-getlasterror).</para>
		/// </returns>
		/// <remarks>
		/// <para>Each page has an associated [page state](/windows/win32/Memory/page-state). The **VirtualAlloc** function can perform the following operations: - Commit a region of reserved pages - Reserve a region of free pages - Simultaneously reserve and commit a region of free pages **VirtualAlloc** cannot reserve a reserved page. It can commit a page that is already committed. This means you can commit a range of pages, regardless of whether they have already been committed, and the function will not fail. You can use **VirtualAlloc** to reserve a block of pages and then make additional calls to **VirtualAlloc** to commit individual pages from the reserved block. This enables a process to reserve a range of its virtual address space without consuming physical storage until it is needed. If the _lpAddress_ parameter is not **NULL**, the function uses the _lpAddress_ and _dwSize_ parameters to compute the region of pages to be allocated. The current state of the entire range of pages must be compatible with the type of allocation specified by the _flAllocationType_ parameter. Otherwise, the function fails and none of the pages are allocated. This compatibility requirement does not preclude committing an already committed page, as mentioned previously. To execute dynamically generated code, use **VirtualAlloc** to allocate memory and the [VirtualProtect](/windows/win32/api/memoryapi/nf-memoryapi-virtualprotect) function to grant **PAGE_EXECUTE** access. The **VirtualAlloc** function can be used to reserve an [Address Windowing Extensions](/windows/win32/Memory/address-windowing-extensions) (AWE) region of memory within the virtual address space of a specified process. This region of memory can then be used to map physical pages into and out of virtual memory as required by the application. The **MEM_PHYSICAL** and **MEM_RESERVE** values must be set in the _AllocationType_ parameter. The **MEM_COMMIT** value must not be set. The page protection must be set to **PAGE_READWRITE**. The [VirtualFree](/windows/win32/api/memoryapi/nf-memoryapi-virtualfree) function can decommit a committed page, releasing the page's storage, or it can simultaneously decommit and release a committed page. It can also release a reserved page, making it a free page. When creating a region that will be executable, the calling program bears responsibility for ensuring cache coherency via an appropriate call to [FlushInstructionCache](/windows/win32/api/processthreadsapi/nf-processthreadsapi-flushinstructioncache) once the code has been set in place. Otherwise attempts to execute code out of the newly executable region may produce unpredictable results.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-virtualalloc#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.1.2600")]
		public static unsafe partial void* VirtualAlloc([Optional] void* lpAddress, nuint dwSize, winmdroot.System.Memory.VIRTUAL_ALLOCATION_TYPE flAllocationType, winmdroot.System.Memory.PAGE_PROTECTION_FLAGS flProtect);

		/// <inheritdoc cref="VirtualProtect(void*, nuint, winmdroot.System.Memory.PAGE_PROTECTION_FLAGS, winmdroot.System.Memory.PAGE_PROTECTION_FLAGS*)"/>
		[SupportedOSPlatform("windows5.1.2600")]
		[OverloadResolutionPriority(1)]
		public static unsafe winmdroot.Foundation.BOOL VirtualProtect(void* lpAddress, nuint dwSize, winmdroot.System.Memory.PAGE_PROTECTION_FLAGS flNewProtect, out winmdroot.System.Memory.PAGE_PROTECTION_FLAGS lpflOldProtect)
		{
			fixed (winmdroot.System.Memory.PAGE_PROTECTION_FLAGS* lpflOldProtectLocal = &lpflOldProtect)
			{
				winmdroot.Foundation.BOOL __result = PInvoke.VirtualProtect(lpAddress, dwSize, flNewProtect, lpflOldProtectLocal);
				return __result;
			}
		}

		/// <summary>Changes the protection on a region of committed pages in the virtual address space of the calling process. (VirtualProtect)</summary>
		/// <param name="lpAddress">
		/// <para>The address of the starting page of the region of pages whose access protection attributes are to be changed. All pages in the specified region must be within the same reserved region allocated when calling the [VirtualAlloc](/windows/win32/api/memoryapi/nf-memoryapi-virtualalloc) or [VirtualAllocEx](/windows/win32/api/memoryapi/nf-memoryapi-virtualallocex) function using **MEM_RESERVE**. The pages cannot span adjacent reserved regions that were allocated by separate calls to **VirtualAlloc** or **VirtualAllocEx** using **MEM_RESERVE**.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-virtualprotect#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="dwSize">The size of the region whose access protection attributes are to be changed, in bytes. The region of affected pages includes all pages containing one or more bytes in the range from the ***lpAddress*** parameter to `(lpAddress+dwSize)`. This means that a 2-byte range  straddling a page boundary causes the protection attributes of both pages to be changed.</param>
		/// <param name="flNewProtect">
		/// <para>The memory protection option. This parameter can be one of the [memory protection constants](/windows/win32/Memory/memory-protection-constants). For mapped views, this value must be compatible with the access protection specified when the view was mapped (see [MapViewOfFile](/windows/win32/api/memoryapi/nf-memoryapi-mapviewoffile), [MapViewOfFileEx](/windows/win32/api/memoryapi/nf-memoryapi-mapviewoffileex), and [MapViewOfFileExNuma](/windows/win32/api/winbase/nf-winbase-mapviewoffileexnuma)).</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-virtualprotect#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="lpflOldProtect">A pointer to a variable that receives the previous access protection value of the first page in the specified region of pages. If this parameter is **NULL** or does not point to a valid variable, the function fails.</param>
		/// <returns>
		/// <para>If the function succeeds, the return value is nonzero. If the function fails, the return value is zero. To get extended error information, call [GetLastError](/windows/win32/api/errhandlingapi/nf-errhandlingapi-getlasterror).</para>
		/// </returns>
		/// <remarks>
		/// <para>You can set the access protection value on committed pages only. If the state of any page in the specified region is not committed, the function fails and returns without modifying the access protection of any pages in the specified region. The **PAGE_GUARD** protection modifier establishes guard pages. Guard pages act as one-shot access alarms. For more information, see [Creating Guard Pages](/windows/win32/Memory/creating-guard-pages). It is best to avoid using **VirtualProtect** to change page protections on memory blocks allocated by [GlobalAlloc](/windows/win32/api/winbase/nf-winbase-globalalloc), [HeapAlloc](/windows/win32/api/heapapi/nf-heapapi-heapalloc), or [LocalAlloc](/windows/win32/api/winbase/nf-winbase-localalloc), because multiple memory blocks can exist on a single page. The heap manager assumes that all pages in the heap grant at least read and write access. When protecting a region that will be executable, the calling program bears responsibility for ensuring cache coherency via an appropriate call to [FlushInstructionCache](/windows/win32/api/processthreadsapi/nf-processthreadsapi-flushinstructioncache) once the code has been set in place.  Otherwise attempts to execute code out of the newly executable region may produce unpredictable results.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-virtualprotect#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.1.2600")]
		public static unsafe partial winmdroot.Foundation.BOOL VirtualProtect(void* lpAddress, nuint dwSize, winmdroot.System.Memory.PAGE_PROTECTION_FLAGS flNewProtect, winmdroot.System.Memory.PAGE_PROTECTION_FLAGS* lpflOldProtect);

		/// <summary>Releases, decommits, or releases and decommits a region of pages within the virtual address space of the calling process.</summary>
		/// <param name="lpAddress">
		/// <para>A pointer to the base address of the region of pages to be freed. If the _dwFreeType_ parameter is **MEM_RELEASE**, this parameter must be the base address returned by the [VirtualAlloc](/windows/win32/api/memoryapi/nf-memoryapi-virtualalloc) function when the region of pages is reserved.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-virtualfree#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="dwSize">
		/// <para>The size of the region of memory to be freed, in bytes. If the _dwFreeType_ parameter is **MEM_RELEASE**, this parameter must be 0 (zero). The function frees the entire region that is reserved in the initial allocation call to [VirtualAlloc](/windows/win32/api/memoryapi/nf-memoryapi-virtualalloc). If the _dwFreeType_ parameter is **MEM_DECOMMIT**, the function decommits all memory pages that contain one or more bytes in the range from the _lpAddress_ parameter to `(lpAddress+dwSize)`. This means, for example, that a 2-byte region of memory that straddles a page boundary causes both pages to be decommitted. If _lpAddress_ is the base address returned by [VirtualAlloc](/windows/win32/api/memoryapi/nf-memoryapi-virtualalloc) and _dwSize_ is 0 (zero), the function decommits the entire region that is allocated by **VirtualAlloc**. After that, the entire region is in the reserved state.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-virtualfree#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="dwFreeType"></param>
		/// <returns>
		/// <para>If the function succeeds, the return value is nonzero. If the function fails, the return value is 0 (zero). To get extended error information, call [GetLastError](/windows/win32/api/errhandlingapi/nf-errhandlingapi-getlasterror).</para>
		/// </returns>
		/// <remarks>
		/// <para>Each page of memory in a process virtual address space has a [Page State](/windows/win32/Memory/page-state). The **VirtualFree** function can decommit a range of pages that are in different states, some committed and some uncommitted. This means that you can decommit a range of pages without first determining the current commitment state of each page. Decommitting a page releases its physical storage, either in memory or in the paging file on disk. If a page is decommitted but not released, its state changes to reserved. Subsequently, you can call [VirtualAlloc](/windows/win32/api/memoryapi/nf-memoryapi-virtualalloc) to commit it, or **VirtualFree** to release it. Attempts to read from or write to a reserved page results in an access violation exception. The **VirtualFree** function can release a range of pages that are in different states, some reserved and some committed. This means that you can release a range of pages without first determining the current commitment state of each page. The entire range of pages originally reserved by the [VirtualAlloc](nf-memoryapi-virtualalloc.md) function must be released at the same time. If a page is released, its state changes to free, and it is available for subsequent allocation operations. After memory is released or decommited, you can never refer to the memory again. Any information that may have been in that memory is gone forever. Attempting to read from or write to a free page results in an access violation exception. If you need to keep information, do not decommit or free memory that contains the information. The **VirtualFree** function can be used on an AWE region of memory, and it invalidates any physical page mappings in the region when freeing the address space. However, the physical page is not deleted, and the application can use them. The application must explicitly call [FreeUserPhysicalPages](nf-memoryapi-freeuserphysicalpages.md) to free the physical pages. When the process is terminated, all resources are cleaned up automatically. **Windows 10, version 1709 and later and Windows 11:** To delete the enclave when you finish using it, call [DeleteEnclave](../enclaveapi/nf-enclaveapi-deleteenclave.md). You cannot delete a VBS enclave by calling the **VirtualFree** or [VirtualFreeEx](nf-memoryapi-virtualfreeex.md) function. You can still delete an SGX enclave by calling **VirtualFree** or **VirtualFreeEx**. **Windows 10, version 1507, Windows 10, version 1511, Windows 10, version 1607 and Windows 10, version 1703:** To delete the enclave when you finish using it, call the **VirtualFree** or [VirtualFreeEx](nf-memoryapi-virtualfreeex.md) function and specify the following values: - The base address of the enclave for the _lpAddress_ parameter. - 0 for the _dwSize_ parameter. - **MEM_RELEASE** for the _dwFreeType_ parameter.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-virtualfree#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.1.2600")]
		public static unsafe partial winmdroot.Foundation.BOOL VirtualFree(void* lpAddress, nuint dwSize, winmdroot.System.Memory.VIRTUAL_FREE_TYPE dwFreeType);

		/// <inheritdoc cref="VirtualAllocEx(winmdroot.Foundation.HANDLE, void*, nuint, winmdroot.System.Memory.VIRTUAL_ALLOCATION_TYPE, winmdroot.System.Memory.PAGE_PROTECTION_FLAGS)"/>
		[SupportedOSPlatform("windows5.1.2600")]
		[OverloadResolutionPriority(1)]
		public static unsafe void* VirtualAllocEx(SafeHandle hProcess, [Optional] void* lpAddress, nuint dwSize, winmdroot.System.Memory.VIRTUAL_ALLOCATION_TYPE flAllocationType, winmdroot.System.Memory.PAGE_PROTECTION_FLAGS flProtect)
		{
			bool hProcessAddRef = false;
			try
			{
				winmdroot.Foundation.HANDLE hProcessLocal;
				if (hProcess is object)
				{
					hProcess.DangerousAddRef(ref hProcessAddRef);
					hProcessLocal = (winmdroot.Foundation.HANDLE)hProcess.DangerousGetHandle();
				}
				else
					throw new ArgumentNullException(nameof(hProcess));
				void* __result = PInvoke.VirtualAllocEx(hProcessLocal, lpAddress, dwSize, flAllocationType, flProtect);
				return __result;
			}
			finally
			{
				if (hProcessAddRef)
					hProcess.DangerousRelease();
			}
		}

		/// <summary>Reserves, commits, or changes the state of a region of memory within the virtual address space of a specified process. The function initializes the memory it allocates to zero. (VirtualAllocEx)</summary>
		/// <param name="hProcess">
		/// <para>The handle to a process. The function allocates memory within the virtual address space of this process. The handle must have the <b>PROCESS_VM_OPERATION</b> access right. For more information, see <a href="https://docs.microsoft.com/windows/desktop/ProcThread/process-security-and-access-rights">Process Security and Access Rights</a>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-virtualallocex#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="lpAddress">
		/// <para>The pointer that specifies a desired starting address for the region of pages that you want to allocate. If you are reserving memory, the function rounds this address down to the nearest multiple of the allocation granularity. If you are committing memory that is already reserved, the function rounds this address down to the nearest page boundary. To determine the size of a page and the allocation granularity on the host computer, use the <a href="https://docs.microsoft.com/windows/desktop/api/sysinfoapi/nf-sysinfoapi-getsysteminfo">GetSystemInfo</a> function. If <i>lpAddress</i> is <b>NULL</b>, the function determines where to allocate the region. If this address is within an enclave that you have not initialized by calling <a href="https://docs.microsoft.com/windows/desktop/api/enclaveapi/nf-enclaveapi-initializeenclave">InitializeEnclave</a>, <b>VirtualAllocEx</b> allocates a page of zeros for the enclave at that address. The page must be previously uncommitted, and will not be measured with the EEXTEND instruction of the Intel Software Guard Extensions programming model. If the address in within an enclave that you initialized, then the allocation operation fails with the <b>ERROR_INVALID_ADDRESS</b> error. That is true for enclaves that do not support dynamic memory management (i.e. SGX1).  SGX2 enclaves will permit allocation, and the page must be accepted by the enclave after it has been allocated.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-virtualallocex#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="dwSize">
		/// <para>The size of the region of memory to allocate, in bytes. If <i>lpAddress</i> is <b>NULL</b>, the function rounds <i>dwSize</i> up to the next page boundary. If <i>lpAddress</i> is not <b>NULL</b>, the function allocates all pages that contain one or more bytes in the range from <i>lpAddress</i> to <i>lpAddress</i>+<i>dwSize</i>. This means, for example, that a 2-byte range that straddles a page boundary causes the function to allocate both pages.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-virtualallocex#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="flAllocationType"></param>
		/// <param name="flProtect">The memory protection for the region of pages to be allocated. If the pages are being committed, you can specify any one of the [memory protection constants](/windows/win32/Memory/memory-protection-constants).</param>
		/// <returns>
		/// <para>If the function succeeds, the return value is the base address of the allocated region of pages. If the function fails, the return value is <b>NULL</b>. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>.</para>
		/// </returns>
		/// <remarks>
		/// <para>Each page has an associated <a href="https://docs.microsoft.com/windows/desktop/Memory/page-state">page state</a>. The <b>VirtualAllocEx</b> function can perform the following operations: </para>
		/// <para>This doc was truncated.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-virtualallocex#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.1.2600")]
		public static unsafe partial void* VirtualAllocEx(winmdroot.Foundation.HANDLE hProcess, [Optional] void* lpAddress, nuint dwSize, winmdroot.System.Memory.VIRTUAL_ALLOCATION_TYPE flAllocationType, winmdroot.System.Memory.PAGE_PROTECTION_FLAGS flProtect);

		/// <inheritdoc cref="VirtualProtectEx(winmdroot.Foundation.HANDLE, void*, nuint, winmdroot.System.Memory.PAGE_PROTECTION_FLAGS, winmdroot.System.Memory.PAGE_PROTECTION_FLAGS*)"/>
		[SupportedOSPlatform("windows5.1.2600")]
		[OverloadResolutionPriority(1)]
		public static unsafe winmdroot.Foundation.BOOL VirtualProtectEx(SafeHandle hProcess, void* lpAddress, nuint dwSize, winmdroot.System.Memory.PAGE_PROTECTION_FLAGS flNewProtect, out winmdroot.System.Memory.PAGE_PROTECTION_FLAGS lpflOldProtect)
		{
			bool hProcessAddRef = false;
			try
			{
				fixed (winmdroot.System.Memory.PAGE_PROTECTION_FLAGS* lpflOldProtectLocal = &lpflOldProtect)
				{
					winmdroot.Foundation.HANDLE hProcessLocal;
					if (hProcess is object)
					{
						hProcess.DangerousAddRef(ref hProcessAddRef);
						hProcessLocal = (winmdroot.Foundation.HANDLE)hProcess.DangerousGetHandle();
					}
					else
						throw new ArgumentNullException(nameof(hProcess));
					winmdroot.Foundation.BOOL __result = PInvoke.VirtualProtectEx(hProcessLocal, lpAddress, dwSize, flNewProtect, lpflOldProtectLocal);
					return __result;
				}
			}
			finally
			{
				if (hProcessAddRef)
					hProcess.DangerousRelease();
			}
		}

		/// <summary>Changes the protection on a region of committed pages in the virtual address space of a specified process.</summary>
		/// <param name="hProcess">A handle to the process whose memory protection is to be changed. The handle must have the **PROCESS_VM_OPERATION** access right. For more information, see [Process Security and Access Rights](/windows/win32/ProcThread/process-security-and-access-rights).</param>
		/// <param name="lpAddress">
		/// <para>A pointer to the base address of the region of pages whose access protection attributes are to be changed. All pages in the specified region must be within the same reserved region allocated when calling the [VirtualAlloc](/windows/win32/api/memoryapi/nf-memoryapi-virtualalloc) or [VirtualAllocEx](/windows/win32/api/memoryapi/nf-memoryapi-virtualallocex) function using **MEM_RESERVE**. The pages cannot span adjacent reserved regions that were allocated by separate calls to **VirtualAlloc** or **VirtualAllocEx** using **MEM_RESERVE**.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-virtualprotectex#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="dwSize">The size of the region whose access protection attributes are changed, in bytes. The region of affected pages includes all pages containing one or more bytes in the range from the _lpAddress_ parameter to `(lpAddress+dwSize)`. This means that a 2-byte range straddling a page boundary causes the protection attributes of both pages to be changed.</param>
		/// <param name="flNewProtect">
		/// <para>The memory protection option. This parameter can be one of the [memory protection constants](/windows/win32/Memory/memory-protection-constants). For mapped views, this value must be compatible with the access protection specified when the view was mapped (see [MapViewOfFile](/windows/win32/api/memoryapi/nf-memoryapi-mapviewoffile), [MapViewOfFileEx](/windows/win32/api/memoryapi/nf-memoryapi-mapviewoffileex), and [MapViewOfFileExNuma](/windows/win32/api/winbase/nf-winbase-mapviewoffileexnuma)).</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-virtualprotectex#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="lpflOldProtect">A pointer to a variable that receives the previous access protection of the first page in the specified region of pages. If this parameter is **NULL** or does not point to a valid variable, the function fails.</param>
		/// <returns>
		/// <para>If the function succeeds, the return value is nonzero. If the function fails, the return value is zero. To get extended error information, call [GetLastError](/windows/win32/api/errhandlingapi/nf-errhandlingapi-getlasterror).</para>
		/// </returns>
		/// <remarks>
		/// <para>The access protection value can be set only on committed pages. If the state of any page in the specified region is not committed, the function fails and returns without modifying the access protection of any pages in the specified region. The **PAGE_GUARD** protection modifier establishes guard pages. Guard pages act as one-shot access alarms. For more information, see [Creating Guard Pages](/windows/win32/Memory/creating-guard-pages). It is best to avoid using **VirtualProtectEx** to change page protections on memory blocks allocated by [GlobalAlloc](/windows/win32/api/winbase/nf-winbase-globalalloc), [HeapAlloc](/windows/win32/api/heapapi/nf-heapapi-heapalloc), or [LocalAlloc](/windows/win32/api/winbase/nf-winbase-localalloc), because multiple memory blocks can exist on a single page. The heap manager assumes that all pages in the heap grant at least read and write access. When protecting a region that will be executable, the calling program bears responsibility for ensuring cache coherency via an appropriate call to [FlushInstructionCache](/windows/win32/api/processthreadsapi/nf-processthreadsapi-flushinstructioncache) once the code has been set in place. Otherwise attempts to execute code out of the newly executable region may produce unpredictable results.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-virtualprotectex#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.1.2600")]
		public static unsafe partial winmdroot.Foundation.BOOL VirtualProtectEx(winmdroot.Foundation.HANDLE hProcess, void* lpAddress, nuint dwSize, winmdroot.System.Memory.PAGE_PROTECTION_FLAGS flNewProtect, winmdroot.System.Memory.PAGE_PROTECTION_FLAGS* lpflOldProtect);

		/// <inheritdoc cref="CreateFileMapping(winmdroot.Foundation.HANDLE, winmdroot.Security.SECURITY_ATTRIBUTES*, winmdroot.System.Memory.PAGE_PROTECTION_FLAGS, uint, uint, winmdroot.Foundation.PCWSTR)"/>
		[SupportedOSPlatform("windows5.1.2600")]
		[OverloadResolutionPriority(1)]
		public static unsafe Microsoft.Win32.SafeHandles.SafeFileHandle CreateFileMapping(SafeHandle hFile, [Optional] winmdroot.Security.SECURITY_ATTRIBUTES? lpFileMappingAttributes, winmdroot.System.Memory.PAGE_PROTECTION_FLAGS flProtect, uint dwMaximumSizeHigh, uint dwMaximumSizeLow, [Optional] string lpName)
		{
			bool hFileAddRef = false;
			try
			{
				fixed (char* lpNameLocal = lpName)
				{
					winmdroot.Foundation.HANDLE hFileLocal;
					if (hFile is object)
					{
						hFile.DangerousAddRef(ref hFileAddRef);
						hFileLocal = (winmdroot.Foundation.HANDLE)hFile.DangerousGetHandle();
					}
					else
						throw new ArgumentNullException(nameof(hFile));
					winmdroot.Security.SECURITY_ATTRIBUTES lpFileMappingAttributesLocal = lpFileMappingAttributes ?? default(winmdroot.Security.SECURITY_ATTRIBUTES);
					Microsoft.Win32.SafeHandles.SafeFileHandle __resultSafeHandle = new Microsoft.Win32.SafeHandles.SafeFileHandle(default, ownsHandle: true);
					winmdroot.Foundation.HANDLE __result = PInvoke.CreateFileMapping(hFileLocal, lpFileMappingAttributes.HasValue ? &lpFileMappingAttributesLocal : null, flProtect, dwMaximumSizeHigh, dwMaximumSizeLow, lpNameLocal);
					global::System.Runtime.InteropServices.Marshal.InitHandle(__resultSafeHandle, __result);
					return __resultSafeHandle;
				}
			}
			finally
			{
				if (hFileAddRef)
