		/// <inheritdoc cref="MapViewOfFile(winmdroot.Foundation.HANDLE, winmdroot.System.Memory.FILE_MAP, uint, uint, nuint)"/>
		[SupportedOSPlatform("windows5.1.2600")]
		[OverloadResolutionPriority(1)]
		public static unsafe winmdroot.System.Memory.MEMORY_MAPPED_VIEW_ADDRESS MapViewOfFile(SafeHandle hFileMappingObject, winmdroot.System.Memory.FILE_MAP dwDesiredAccess, uint dwFileOffsetHigh, uint dwFileOffsetLow, nuint dwNumberOfBytesToMap)
		{
