			}
		}

		/// <summary>Maps a view of a file mapping into the address space of a calling process.</summary>
		/// <param name="hFileMappingObject">
		/// <para>A handle to a file mapping object. The <a href="https://docs.microsoft.com/windows/desktop/api/winbase/nf-winbase-createfilemappinga">CreateFileMapping</a> and <a href="https://docs.microsoft.com/windows/desktop/api/winbase/nf-winbase-openfilemappinga">OpenFileMapping</a> functions return this handle.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-mapviewoffile#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="dwDesiredAccess">The type of access to a file mapping object, which determines the page protection of the pages. This</param>
		/// <param name="dwFileOffsetHigh">A high-order <b>DWORD</b> of the file offset where the view begins.</param>
		/// <param name="dwFileOffsetLow">
		/// <para>A low-order <b>DWORD</b> of the file offset where the view is to begin. The combination of the high and low offsets must specify an offset within the file mapping. They must also match the  memory allocation granularity of the system. That is, the offset must be a multiple of the allocation granularity. To obtain the memory allocation granularity of the system, use the <a href="https://docs.microsoft.com/windows/desktop/api/sysinfoapi/nf-sysinfoapi-getsysteminfo">GetSystemInfo</a> function, which fills in the members of a <a href="https://docs.microsoft.com/windows/desktop/api/sysinfoapi/ns-sysinfoapi-system_info">SYSTEM_INFO</a> structure.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-mapviewoffile#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="dwNumberOfBytesToMap">
		/// <para>The number of bytes of a file mapping to map to the view. All bytes must be within the maximum size specified by <a href="https://docs.microsoft.com/windows/desktop/api/winbase/nf-winbase-createfilemappinga">CreateFileMapping</a>. If this parameter is 0 (zero), the mapping extends from the specified offset to the end of the file mapping.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-mapviewoffile#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <returns>
		/// <para>If the function succeeds, the return value is the starting address of the mapped view. If the function fails, the return value is <b>NULL</b>. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>.</para>
		/// </returns>
		/// <remarks>
		/// <para>Mapping a file makes the specified portion of a file visible in the address space of the calling process. For files that are larger than the address space, you can only map a small portion of the file data at one time. When the first view is complete, you can unmap it and map a new view. To obtain the size of a view, use the <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-virtualquery">VirtualQuery</a> function. Multiple views of a file (or a file mapping object and its mapped file) are <i>coherent</i> if they contain identical data at a specified time. This occurs if the file views are derived from any file mapping object that is backed by the same file. A process can duplicate a file mapping object handle into another process by using the <a href="https://docs.microsoft.com/windows/desktop/api/handleapi/nf-handleapi-duplicatehandle">DuplicateHandle</a> function, or another process can open a file mapping object by name by using the <a href="https://docs.microsoft.com/windows/desktop/api/winbase/nf-winbase-openfilemappinga">OpenFileMapping</a> function. With one important exception, file views derived from any file mapping object that is backed by the same file are coherent or identical at a specific time. Coherency is guaranteed for views within a process and for views that are mapped by different processes. The exception is related to remote files. Although <b>MapViewOfFile</b> works with remote files, it does not keep them coherent. For example, if two computers both map a file as writable, and both change the same page, each computer only sees its own writes to the page. When the data gets updated on the disk, it is not merged. A mapped view of a file is not guaranteed to be coherent with a file that is being accessed by the <a href="https://docs.microsoft.com/windows/desktop/api/fileapi/nf-fileapi-readfile">ReadFile</a> or <a href="https://docs.microsoft.com/windows/desktop/api/fileapi/nf-fileapi-writefile">WriteFile</a> function. Do not store pointers in the memory mapped file; store offsets from the base of the file mapping so that the mapping can be used at any address. To guard against <b>EXCEPTION_IN_PAGE_ERROR</b> exceptions, use structured exception handling to protect any code that writes to or reads from a memory mapped view of a file other than the page file. For more information, see <a href="https://docs.microsoft.com/windows/desktop/Memory/reading-and-writing-from-a-file-view">Reading and Writing From a File View</a>. When modifying a file through a mapped view, the last modification timestamp may not be updated automatically. If required, the caller should use <a href="https://docs.microsoft.com/windows/desktop/api/fileapi/nf-fileapi-setfiletime">SetFileTime</a> to set the timestamp. If a file mapping object is backed by the paging file (<a href="https://docs.microsoft.com/windows/desktop/api/winbase/nf-winbase-createfilemappinga">CreateFileMapping</a> is called with the <i>hFile</i> parameter set to <b>INVALID_HANDLE_VALUE</b>), the paging file must be large enough to hold the entire mapping. If it is not, <b>MapViewOfFile</b> fails. The initial contents of the pages in a file mapping object backed by the paging file are 0 (zero). When a file mapping object that is backed by the paging file is created, the caller can  specify whether <b>MapViewOfFile</b> should reserve and commit pages at the same time (<b>SEC_COMMIT</b>) or  simply reserve pages (<b>SEC_RESERVE</b>). Mapping the file makes the entire mapped virtual address range unavailable to other allocations in the process. After a page from the reserved range is committed, it cannot be freed or decommitted by calling <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-virtualfree">VirtualFree</a>. Reserved and committed pages are released when the view is unmapped and the file mapping object is closed. For details, see the <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-unmapviewoffile">UnmapViewOfFile</a> and <a href="https://docs.microsoft.com/windows/desktop/api/handleapi/nf-handleapi-closehandle">CloseHandle</a> functions. To have a file with executable permissions, an application must call <a href="https://docs.microsoft.com/windows/desktop/api/winbase/nf-winbase-createfilemappinga">CreateFileMapping</a> with either <b>PAGE_EXECUTE_READWRITE</b> or <b>PAGE_EXECUTE_READ</b>, and then call <b>MapViewOfFile</b> with <b>FILE_MAP_EXECUTE</b> | <b>FILE_MAP_WRITE</b> or <b>FILE_MAP_EXECUTE</b> | <b>FILE_MAP_READ</b>. In Windows Server 2012, this function is supported by the following technologies. </para>
		/// <para>This doc was truncated.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-mapviewoffile#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.1.2600")]
		public static partial winmdroot.System.Memory.MEMORY_MAPPED_VIEW_ADDRESS MapViewOfFile(winmdroot.Foundation.HANDLE hFileMappingObject, winmdroot.System.Memory.FILE_MAP dwDesiredAccess, uint dwFileOffsetHigh, uint dwFileOffsetLow, nuint dwNumberOfBytesToMap);

		/// <inheritdoc cref="MapViewOfFileEx(winmdroot.Foundation.HANDLE, winmdroot.System.Memory.FILE_MAP, uint, uint, nuint, void*)"/>
