				winmdroot.System.Memory.MEMORY_MAPPED_VIEW_ADDRESS __result = PInvoke.MapViewOfFileEx(hFileMappingObjectLocal, dwDesiredAccess, dwFileOffsetHigh, dwFileOffsetLow, dwNumberOfBytesToMap, lpBaseAddress);
