		/// <summary>Retrieves the addresses of the pages that are written to in a region of virtual memory.</summary>
		/// <param name="dwFlags">
		/// <para>Indicates whether the function resets the write-tracking state. To reset the write-tracking state, set this parameter to <b>WRITE_WATCH_FLAG_RESET</b>. If this parameter is 0 (zero), <b>GetWriteWatch</b> does not reset the write-tracking state. For more information, see the Remarks section of this topic.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-getwritewatch#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="lpBaseAddress">
		/// <para>The base address of the memory region for which to retrieve write-tracking information. This address must be in a memory region that is allocated by the <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-virtualalloc">VirtualAlloc</a> function using <b>MEM_WRITE_WATCH</b>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-getwritewatch#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="dwRegionSize">The size of the memory region for which to retrieve write-tracking information, in bytes.</param>
		/// <param name="lpAddresses">
		/// <para>A pointer to a buffer that receives an array of page addresses in the memory region. The addresses indicate the pages that have been written to since the region has been allocated or the write-tracking state has been reset.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-getwritewatch#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="lpdwCount">
		/// <para>On input, this variable indicates the size of the <i>lpAddresses</i> array, in array elements. On output, the variable receives the number of page addresses that are returned in the array.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-getwritewatch#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="lpdwGranularity">A pointer to a variable that receives the page size, in bytes.</param>
		/// <returns>
		/// <para>If the function succeeds, the return value is 0 (zero). If the function fails, the return value is a nonzero value.</para>
		/// </returns>
		/// <remarks>
		/// <para>When you call the <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-virtualalloc">VirtualAlloc</a> function to reserve or commit memory, you can specify <b>MEM_WRITE_WATCH</b>. This value causes the system to keep track of the pages that are written to in the committed memory region. You can call the <b>GetWriteWatch</b> function to retrieve the addresses of the pages that have been written to since the region has been allocated or the write-tracking state has been reset. To reset the write-tracking state, set the <b>WRITE_WATCH_FLAG_RESET</b> value in the <i>dwFlags</i> parameter. Alternatively, you can call the <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-resetwritewatch">ResetWriteWatch</a> function to reset the write-tracking state. However, if you use <b>ResetWriteWatch</b>,  you must ensure that no threads write to the region during the interval between the <b>GetWriteWatch</b> and <b>ResetWriteWatch</b> calls. Otherwise, there may be written pages that you do not detect. The <b>GetWriteWatch</b> function can be useful to profilers, debugging tools, or garbage collectors.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-getwritewatch#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll"),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.1.2600")]
		public static unsafe partial uint GetWriteWatch(uint dwFlags, void* lpBaseAddress, nuint dwRegionSize, [Optional] void** lpAddresses, [Optional] nuint* lpdwCount, [Optional] uint* lpdwGranularity);

		/// <summary>Resets the write-tracking state for a region of virtual memory. Subsequent calls to the GetWriteWatch function only report pages that are written to since the reset operation.</summary>
		/// <param name="lpBaseAddress">
		/// <para>A pointer to the base address of the memory region for which to reset the write-tracking state. This address must be in a memory region that is allocated by the <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-virtualalloc">VirtualAlloc</a> function with <b>MEM_WRITE_WATCH</b>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-resetwritewatch#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="dwRegionSize">The size of the memory region for which to reset the write-tracking information, in bytes.</param>
		/// <returns>
		/// <para>If the function succeeds, the return value is 0 (zero). If the function fails, the return value is a nonzero value.</para>
		/// </returns>
		/// <remarks>
		/// <para>The <b>ResetWriteWatch</b> function can be useful to an application such as a garbage collector. The application calls the <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-getwritewatch">GetWriteWatch</a> function to retrieve the list of written pages, and then writes to those pages as part of its cleanup operation. Then the garbage collector calls <b>ResetWriteWatch</b> to remove the write-tracking records caused by the cleanup. You can also reset the write-tracking state of a memory region by specifying <b>WRITE_WATCH_FLAG_RESET</b> when you call <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-getwritewatch">GetWriteWatch</a>. If you use <b>ResetWriteWatch</b>, you must ensure that no threads write to the region during the interval between the <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-getwritewatch">GetWriteWatch</a> and <b>ResetWriteWatch</b> calls. Otherwise, there may be written pages that you not detect.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-resetwritewatch#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll"),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.1.2600")]
		public static unsafe partial uint ResetWriteWatch(void* lpBaseAddress, nuint dwRegionSize);

