		/// <inheritdoc cref="QueryMemoryResourceNotification(winmdroot.Foundation.HANDLE, winmdroot.Foundation.BOOL*)"/>
		[SupportedOSPlatform("windows5.1.2600")]
		[OverloadResolutionPriority(1)]
		public static unsafe winmdroot.Foundation.BOOL QueryMemoryResourceNotification(SafeHandle ResourceNotificationHandle, out winmdroot.Foundation.BOOL ResourceState)
		{
			bool ResourceNotificationHandleAddRef = false;
			try
			{
				fixed (winmdroot.Foundation.BOOL* ResourceStateLocal = &ResourceState)
				{
					winmdroot.Foundation.HANDLE ResourceNotificationHandleLocal;
					if (ResourceNotificationHandle is object)
					{
						ResourceNotificationHandle.DangerousAddRef(ref ResourceNotificationHandleAddRef);
						ResourceNotificationHandleLocal = (winmdroot.Foundation.HANDLE)ResourceNotificationHandle.DangerousGetHandle();
					}
					else
						throw new ArgumentNullException(nameof(ResourceNotificationHandle));
					winmdroot.Foundation.BOOL __result = PInvoke.QueryMemoryResourceNotification(ResourceNotificationHandleLocal, ResourceStateLocal);
					return __result;
				}
			}
			finally
			{
				if (ResourceNotificationHandleAddRef)
					ResourceNotificationHandle.DangerousRelease();
			}
		}

