		/// <param name="dwMaximumSizeLow">
		/// <para>The low-order <b>DWORD</b> of the maximum size of the file mapping object. If this parameter and the <i>dwMaximumSizeHigh</i> parameter are 0 (zero), the maximum size of the file mapping object is equal to the current size of the file that the <i>hFile</i> parameter identifies. An attempt to map a file with a length of 0 (zero) fails with an error code of <b>ERROR_FILE_INVALID</b>. Applications should test for files with a length of 0 (zero) and reject those files.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-createfilemappingnumaw#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="lpName">
