		/// </returns>
		/// <remarks>For more information about the behavior of this function, see the <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-unmapviewoffile">UnmapViewOfFile</a> function.</remarks>
		[LibraryImport("KERNEL32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
