		/// <summary>Frees physical memory pages that are allocated previously by using AllocateUserPhysicalPages or AllocateUserPhysicalPagesNuma.</summary>
		/// <param name="hProcess">
		/// <para>The handle to a process. The function frees memory within the virtual address space of this process.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-freeuserphysicalpages#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="NumberOfPages">
		/// <para>The size of the physical memory to free, in pages. On return, if the function fails, this parameter indicates the number of pages that are freed.</para>
