		/// </param>
		/// <param name="PageArray">A pointer to an array of page frame numbers of the allocated memory to be freed.</param>
		/// <returns>
		/// <para>If the function succeeds, the return value is <b>TRUE</b>. If the function fails, the return value is <b>FALSE</b>. In this case, the <i>NumberOfPages</i> parameter reflect how many pages have actually been released. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>.</para>
		/// </returns>
		/// <remarks>
		/// <para>In a multiprocessor environment, this function maintains coherence of the hardware translation buffer. When this function returns, all threads on all processors are guaranteed to see the correct mapping. To compile an application that uses this function, define the _WIN32_WINNT macro as 0x0500 or later. For more information, see <a href="https://docs.microsoft.com/windows/desktop/WinProg/using-the-windows-headers">Using the Windows Headers</a>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-freeuserphysicalpages#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.1.2600")]
		public static unsafe partial winmdroot.Foundation.BOOL FreeUserPhysicalPages(winmdroot.Foundation.HANDLE hProcess, nuint* NumberOfPages, nuint* PageArray);

		/// <inheritdoc cref="MapUserPhysicalPages(void*, nuint, nuint*)"/>
		[SupportedOSPlatform("windows5.1.2600")]
