				return __result;
			}
		}

		/// <summary>Maps previously allocated physical memory pages at a specified address in an Address Windowing Extensions (AWE) region. (MapUserPhysicalPages)</summary>
		/// <param name="VirtualAddress">
		/// <para>A pointer to the starting address of the region of memory to remap. The value of <i>lpAddress</i> must be within the address range that the <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-virtualalloc">VirtualAlloc</a> function returns when the <a href="https://docs.microsoft.com/windows/desktop/Memory/address-windowing-extensions">Address Windowing Extensions</a> (AWE) region is allocated.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-mapuserphysicalpages#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="NumberOfPages">
		/// <para>The size of the physical memory and virtual address space for which to establish translations, in pages. The virtual address range is contiguous starting at <i>lpAddress</i>. The physical frames are specified by the <i>UserPfnArray</i>. The total number of pages cannot extend from the starting address beyond the end of the range that is specified in <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-allocateuserphysicalpages">AllocateUserPhysicalPages</a>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-mapuserphysicalpages#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="PageArray">
		/// <para>A pointer to an array of physical page frame numbers. These frames are mapped by the argument <i>lpAddress</i> on return from this function. The size of the memory that is allocated should be at least the <i>NumberOfPages</i> times the size of the data type <b>ULONG_PTR</b>.</para>
		/// <para>Do not attempt to modify this buffer. It contains operating system data, and corruption could be catastrophic. The information in the buffer is not useful to an application. If this parameter is <b>NULL</b>, the specified address range is unmapped.  Also, the specified physical pages are not freed, and you must call <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-freeuserphysicalpages">FreeUserPhysicalPages</a> to free them.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-mapuserphysicalpages#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <returns>
		/// <para>If the function succeeds, the return value is <b>TRUE</b>. If the function fails, the return value is <b>FALSE</b> and no mapping is done—partial or otherwise. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>.</para>
		/// </returns>
		/// <remarks>
		/// <para>The physical pages are unmapped but they are not freed. You must call <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-freeuserphysicalpages">FreeUserPhysicalPages</a> to free the physical pages. Any number of physical memory pages can be specified, but the memory must  not extend outside the virtual address space that <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-virtualalloc">VirtualAlloc</a> allocates. Any existing address maps are automatically overwritten with the new translations, and the old translations are unmapped. You cannot map physical memory pages outside the range that is specified in <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-allocateuserphysicalpages">AllocateUserPhysicalPages</a>. You can map multiple regions simultaneously, but they cannot overlap. Physical pages can be located at any physical address, but do not make assumptions about the contiguity of the physical pages. To unmap the current address range, specify <b>NULL</b> as the physical memory page array parameter. Any currently mapped pages are unmapped, but are not freed. You must call <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-freeuserphysicalpages">FreeUserPhysicalPages</a> to free the physical pages. In a multiprocessor environment, this function maintains hardware translation buffer coherence. On return from this function, all threads on all processors are guaranteed to see the correct mapping. To compile an application that uses this function, define the _WIN32_WINNT macro as 0x0500 or later. For more information, see <a href="https://docs.microsoft.com/windows/desktop/WinProg/using-the-windows-headers">Using the Windows Headers</a>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-mapuserphysicalpages#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.1.2600")]
