						}
						else
							throw new ArgumentNullException(nameof(hProcess));
						winmdroot.Foundation.BOOL __result = PInvoke.AllocateUserPhysicalPagesNuma(hProcessLocal, NumberOfPagesLocal, PageArrayLocal, nndPreferred);
