		/// <summary>Indicates that the data contained in a range of memory pages is no longer needed by the application and can be discarded by the system if necessary.</summary>
		/// <param name="VirtualAddress">Page-aligned starting address of the memory to offer.</param>
		/// <param name="Size">Size, in bytes, of the memory region to offer.  <i>Size</i> must be an integer multiple of the system page size.</param>
		/// <param name="Priority">
		/// <para><i>Priority</i> indicates how important the offered memory is to the application. A higher priority increases the probability that the offered memory can be reclaimed intact when calling <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-reclaimvirtualmemory">ReclaimVirtualMemory</a>. The system typically discards lower priority memory before discarding higher priority memory.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-offervirtualmemory#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <returns>ERROR_SUCCESS if successful; a <a href="https://docs.microsoft.com/windows/desktop/Debug/system-error-codes">System Error Code</a> otherwise.</returns>
		/// <remarks>
		/// <para>To reclaim offered pages, call <a href="https://docs.microsoft.com/windows/desktop/api/memoryapi/nf-memoryapi-reclaimvirtualmemory">ReclaimVirtualMemory</a>. The data in reclaimed pages may have been discarded, in which case the contents of the memory region is undefined and must be rewritten by the application. Do not call <b>OfferVirtualMemory</b> to offer virtual memory that is locked. Doing so will unlock the specified range of pages. Note that offering and reclaiming virtual memory is similar to using the MEM_RESET and MEM_RESET_UNDO memory allocation flags, except that <b>OfferVirtualMemory</b> removes the memory from the process working set and restricts access to the offered pages until they are reclaimed.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-offervirtualmemory#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll"),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows8.1")]
		public static unsafe partial uint OfferVirtualMemory(void* VirtualAddress, nuint Size, winmdroot.System.Memory.OFFER_PRIORITY Priority);

		/// <summary>Reclaims a range of memory pages that were offered to the system with OfferVirtualMemory.</summary>
		/// <param name="VirtualAddress">Page-aligned starting address of the memory to reclaim.</param>
		/// <param name="Size">Size, in bytes, of the memory region to reclaim.  <i>Size</i> must be an integer multiple of the system page size.</param>
		/// <returns>
		/// <para>Returns ERROR_SUCCESS if successful and the memory was reclaimed intact. Returns ERROR_BUSY if successful but the memory was discarded and must be rewritten by the application.  In this case, the contents of the memory region is undefined. Returns a <a href="https://docs.microsoft.com/windows/desktop/Debug/system-error-codes">System Error Code</a> otherwise.</para>
		/// </returns>
		/// <remarks>
		/// <para>Reclaimed memory pages can be used by the application, and will be written to the system paging file if paging occurs. If the function returns ERROR_SUCCESS, the data in the reclaimed pages is valid. If the function returns ERROR_BUSY, the data in the reclaimed pages was discarded by the system and is no longer valid. For this reason, memory should only be offered to the system if the application does not need or can regenerate the data.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/memoryapi/nf-memoryapi-reclaimvirtualmemory#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll"),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows8.1")]
		public static unsafe partial uint ReclaimVirtualMemory(void* VirtualAddress, nuint Size);

