		/// <inheritdoc cref="EnableThreadProfiling(winmdroot.Foundation.HANDLE, uint, ulong, winmdroot.Foundation.HANDLE*)"/>
		[SupportedOSPlatform("windows6.1")]
		[OverloadResolutionPriority(1)]
		public static unsafe uint EnableThreadProfiling(SafeHandle ThreadHandle, uint Flags, ulong HardwareCounters, out Microsoft.Win32.SafeHandles.SafeFileHandle PerformanceDataHandle)
		{
			bool ThreadHandleAddRef = false;
			try
			{
				winmdroot.Foundation.HANDLE ThreadHandleLocal;
				if (ThreadHandle is object)
				{
					ThreadHandle.DangerousAddRef(ref ThreadHandleAddRef);
					ThreadHandleLocal = (winmdroot.Foundation.HANDLE)ThreadHandle.DangerousGetHandle();
				}
				else
					throw new ArgumentNullException(nameof(ThreadHandle));
				winmdroot.Foundation.HANDLE PerformanceDataHandleLocal;
				PerformanceDataHandle = new Microsoft.Win32.SafeHandles.SafeFileHandle(default, ownsHandle: true);
				uint __result = PInvoke.EnableThreadProfiling(ThreadHandleLocal, Flags, HardwareCounters, &PerformanceDataHandleLocal);
				global::System.Runtime.InteropServices.Marshal.InitHandle(PerformanceDataHandle, PerformanceDataHandleLocal);
				return __result;
			}
			finally
			{
				if (ThreadHandleAddRef)
					ThreadHandle.DangerousRelease();
			}
		}

		/// <summary>Enables thread profiling on the specified thread.</summary>
