		/// <para>This doc was truncated.</para>
		/// </returns>
		/// <remarks>
		/// <para>FLS indexes are typically allocated by the <a href="https://docs.microsoft.com/windows/desktop/api/fibersapi/nf-fibersapi-flsalloc">FlsAlloc</a> function during process or DLL initialization. After an FLS index is allocated, each fiber of the process can use it to access its own FLS slot for that index. A thread specifies an FLS index in a call to <b>FlsSetValue</b> to store a value in its slot. The thread specifies the same index in a subsequent call to <a href="https://docs.microsoft.com/windows/desktop/api/fibersapi/nf-fibersapi-flsgetvalue">FlsGetValue</a> to retrieve the stored value.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/fibersapi/nf-fibersapi-flssetvalue#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows6.0.6000")]
		public static unsafe partial winmdroot.Foundation.BOOL FlsSetValue(uint dwFlsIndex, [Optional] void* lpFlsData);

		/// <summary>Releases a fiber local storage (FLS) index, making it available for reuse.</summary>
		/// <param name="dwFlsIndex">
		/// <para>The FLS index that was allocated by the <a href="https://docs.microsoft.com/windows/desktop/api/fibersapi/nf-fibersapi-flsalloc">FlsAlloc</a> function.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/fibersapi/nf-fibersapi-flsfree#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <returns>
		/// <para>If the function succeeds, the return value is nonzero. If the function fails, the return value is zero. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>.</para>
		/// </returns>
		/// <remarks>
		/// <para>Freeing an FLS index frees the index for all instances of FLS in the current process. Freeing an FLS index also causes the associated callback routine to be called for each fiber, if the corresponding FLS slot contains a non-NULL value. If the fibers of the process have allocated memory and stored a pointer to the memory in an FLS slot, they should free the memory before calling <b>FlsFree</b>. The <b>FlsFree</b> function does not free memory blocks whose addresses have been stored in the FLS slots associated with the FLS index. It is expected that DLLs call this function (if at all) only during DLL_PROCESS_DETACH.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/fibersapi/nf-fibersapi-flsfree#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows6.0.6000")]
		public static partial winmdroot.Foundation.BOOL FlsFree(uint dwFlsIndex);

