		[SupportedOSPlatform("windows6.0.6000")]
		public static unsafe partial winmdroot.Foundation.BOOL SleepConditionVariableCS(winmdroot.System.Threading.CONDITION_VARIABLE* ConditionVariable, winmdroot.System.Threading.CRITICAL_SECTION* CriticalSection, uint dwMilliseconds);

