		[SupportedOSPlatform("windows5.1.2600")]
		[OverloadResolutionPriority(1)]
		public static unsafe winmdroot.Foundation.BOOL SetEvent(SafeHandle hEvent)
		{
			bool hEventAddRef = false;
			try
			{
				winmdroot.Foundation.HANDLE hEventLocal;
				if (hEvent is object)
				{
					hEvent.DangerousAddRef(ref hEventAddRef);
					hEventLocal = (winmdroot.Foundation.HANDLE)hEvent.DangerousGetHandle();
				}
				else
					throw new ArgumentNullException(nameof(hEvent));
				winmdroot.Foundation.BOOL __result = PInvoke.SetEvent(hEventLocal);
				return __result;
			}
			finally
			{
				if (hEventAddRef)
					hEvent.DangerousRelease();
			}
		}

