		public static unsafe partial winmdroot.Foundation.HANDLE CreateMutex([Optional] winmdroot.Security.SECURITY_ATTRIBUTES* lpMutexAttributes, winmdroot.Foundation.BOOL bInitialOwner, [Optional] winmdroot.Foundation.PCWSTR lpName);

