		/// <inheritdoc cref="CreateProcess(winmdroot.Foundation.PCWSTR, winmdroot.Foundation.PWSTR, winmdroot.Security.SECURITY_ATTRIBUTES*, winmdroot.Security.SECURITY_ATTRIBUTES*, winmdroot.Foundation.BOOL, winmdroot.System.Threading.PROCESS_CREATION_FLAGS, void*, winmdroot.Foundation.PCWSTR, winmdroot.System.Threading.STARTUPINFOW*, winmdroot.System.Threading.PROCESS_INFORMATION*)"/>
