		{
			if (lpCommandLine != null && lpCommandLine.LastIndexOf('\0') == -1)				throw new ArgumentException("Required null terminator missing.", "lpCommandLine");
			fixed (winmdroot.System.Threading.PROCESS_INFORMATION* lpProcessInformationLocal = &lpProcessInformation)
			{
				fixed (winmdroot.System.Threading.STARTUPINFOW* lpStartupInfoLocal = &lpStartupInfo)
				{
					fixed (char* lpCurrentDirectoryLocal = lpCurrentDirectory)
					{
						fixed (char* plpCommandLine = lpCommandLine)
						{
