							{
								winmdroot.Foundation.PWSTR wstrlpCommandLine = plpCommandLine;
								winmdroot.Security.SECURITY_ATTRIBUTES lpProcessAttributesLocal = lpProcessAttributes ?? default(winmdroot.Security.SECURITY_ATTRIBUTES);
