		public static unsafe winmdroot.Foundation.BOOL UpdateProcThreadAttribute(winmdroot.System.Threading.LPPROC_THREAD_ATTRIBUTE_LIST lpAttributeList, uint dwFlags, nuint Attribute, [Optional] ReadOnlySpan<byte> lpValue, [Optional] Span<byte> lpPreviousValue, [Optional] nuint? lpReturnSize)
