		/// <summary>Retrieves the processor mask for a node regardless of the processor group the node belongs to.</summary>
		/// <param name="Node">The node number.</param>
		/// <param name="ProcessorMask">
		/// <para>A pointer to a <a href="https://docs.microsoft.com/windows/desktop/api/winnt/ns-winnt-group_affinity">GROUP_AFFINITY</a> structure that receives the processor mask for the specified node. A processor mask is a bit vector in which each bit represents a processor and whether it is in the node. If the specified node has no processors configured, the <b>Mask</b> member is zero and the <b>Group</b> member is undefined.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/systemtopologyapi/nf-systemtopologyapi-getnumanodeprocessormaskex#parameters">Read more on learn.microsoft.com</see>.</para>
