		/// <summary>Retrieves the multi-group processor mask of the specified node.</summary>
		/// <param name="NodeNumber">Supplies the zero-based node number for the node of interest.</param>
		/// <param name="ProcessorMasks">
		/// <para>An array of [GROUP_AFFINITY](../winnt/ns-winnt-group_affinity.md) structures, which upon successful return describes the processor mask of the specified node. Each element in the array describes a set of processors that belong to the node within a single processor group. There will be one element in the resulting array for each processor group this node has active processors in.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/systemtopologyapi/nf-systemtopologyapi-getnumanodeprocessormask2#parameters">Read more on learn.microsoft.com</see>.</para>
