		public static unsafe partial winmdroot.Foundation.BOOL GetNumaNodeProcessorMask2(ushort NodeNumber, [Optional] winmdroot.System.SystemInformation.GROUP_AFFINITY* ProcessorMasks, ushort ProcessorMaskCount, ushort* RequiredMaskCount);

