		/// <summary>Retrieves the process affinity mask for the specified process and the system affinity mask for the system.</summary>
		/// <param name="hProcess">
		/// <para>A handle to the process whose affinity mask is desired. This handle must have the <b>PROCESS_QUERY_INFORMATION</b> or <b>PROCESS_QUERY_LIMITED_INFORMATION</b> access right. For more information, see <a href="https://docs.microsoft.com/windows/desktop/ProcThread/process-security-and-access-rights">Process Security and Access Rights</a>. <b>Windows Server 2003 and Windows XP:  </b>The handle must have the <b>PROCESS_QUERY_INFORMATION</b> access right.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winbase/nf-winbase-getprocessaffinitymask#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <param name="lpProcessAffinityMask">A pointer to a variable that receives the affinity mask for the specified process.</param>
		/// <param name="lpSystemAffinityMask">A pointer to a variable that receives the affinity mask for the system.</param>
		/// <returns>
		/// <para>If the function succeeds, the return value is nonzero and the function sets the variables pointed to by <i>lpProcessAffinityMask</i> and <i>lpSystemAffinityMask</i> to the appropriate affinity masks. On a system with more than 64 processors, if the threads of the calling process are in a single <a href="https://docs.microsoft.com/windows/desktop/ProcThread/processor-groups">processor group</a>, the function sets the variables pointed to by <i>lpProcessAffinityMask</i> and <i>lpSystemAffinityMask</i> to the process affinity mask and the processor mask of active logical processors for that group. If the calling process contains threads in multiple groups, the function returns zero for both affinity masks. If the function fails, the return value is zero, and the values of the variables pointed to by <i>lpProcessAffinityMask</i> and <i>lpSystemAffinityMask</i> are undefined. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>.</para>
		/// </returns>
		/// <remarks>
		/// <para>A process affinity mask is a bit vector in which each bit represents the processors that a process is allowed to run on. A system affinity mask is a bit vector in which each bit represents the processors that are configured into a system. A process affinity mask is a subset of the system affinity mask. A process is only allowed to run on the processors configured into a system. Therefore, the process affinity mask cannot specify a 1 bit for a processor when the system affinity mask specifies a 0 bit for that processor. Starting with Windows 11 and Windows Server 2022, on a system with more than 64 processors, process and thread affinities span all processors in the system, across all <a href="https://docs.microsoft.com/windows/desktop/ProcThread/processor-groups">processor groups</a>, by default. The <b>GetProcessAffinityMask</b> function sets the <i>lpProcessAffinityMask</i> and <i>lpSystemAffinityMask</i> to the process and system processor masks over the process' primary group. If the process had explicitly set the affinity of one or more of its threads outside of the process' primary group, the function returns zero for both affinity masks. If, however, <i>hHandle</i> specifies a handle to the current process, the function always uses the calling thread's primary group (which by default is the same as the process' primary group) in order to set the <i>lpProcessAffinityMask</i> and <i>lpSystemAffinityMask</i>.</para>
		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winbase/nf-winbase-getprocessaffinitymask#">Read more on learn.microsoft.com</see>.</para>
		/// </remarks>
		[LibraryImport("KERNEL32.dll", SetLastError = true),DefaultDllImportSearchPaths(DllImportSearchPath.System32)]
		[SupportedOSPlatform("windows5.1.2600")]
		public static unsafe partial winmdroot.Foundation.BOOL GetProcessAffinityMask(winmdroot.Foundation.HANDLE hProcess, nuint* lpProcessAffinityMask, nuint* lpSystemAffinityMask);

		/// <inheritdoc cref="SetProcessAffinityMask(winmdroot.Foundation.HANDLE, nuint)"/>
		[SupportedOSPlatform("windows5.1.2600")]
		[OverloadResolutionPriority(1)]
		public static unsafe winmdroot.Foundation.BOOL SetProcessAffinityMask(SafeHandle hProcess, nuint dwProcessAffinityMask)
		{
			bool hProcessAddRef = false;
			try
			{
				winmdroot.Foundation.HANDLE hProcessLocal;
				if (hProcess is object)
				{
					hProcess.DangerousAddRef(ref hProcessAddRef);
					hProcessLocal = (winmdroot.Foundation.HANDLE)hProcess.DangerousGetHandle();
				}
				else
					throw new ArgumentNullException(nameof(hProcess));
				winmdroot.Foundation.BOOL __result = PInvoke.SetProcessAffinityMask(hProcessLocal, dwProcessAffinityMask);
				return __result;
			}
			finally
