		/// <para><see href="https://learn.microsoft.com/windows/win32/api/winbase/nf-winbase-dequeueumscompletionlistitems#parameters">Read more on learn.microsoft.com</see>.</para>
		/// </param>
		/// <returns>
		/// <para>If the function succeeds, it returns a nonzero value. If the function fails, the return value is zero. To get extended error information, call <a href="https://docs.microsoft.com/windows/desktop/api/errhandlingapi/nf-errhandlingapi-getlasterror">GetLastError</a>. Possible error values include the following. </para>
		/// <para>This doc was truncated.</para>
		/// </returns>
