		[OverloadResolutionPriority(1)]
		public static unsafe winmdroot.Foundation.BOOL AreShortNamesEnabled(SafeHandle Handle, out winmdroot.Foundation.BOOL Enabled)
		{
			bool HandleAddRef = false;
			try
			{
				fixed (winmdroot.Foundation.BOOL* EnabledLocal = &Enabled)
				{
					winmdroot.Foundation.HANDLE HandleLocal;
					if (Handle is object)
					{
						Handle.DangerousAddRef(ref HandleAddRef);
						HandleLocal = (winmdroot.Foundation.HANDLE)Handle.DangerousGetHandle();
					}
					else
						throw new ArgumentNullException(nameof(Handle));
					winmdroot.Foundation.BOOL __result = PInvoke.AreShortNamesEnabled(HandleLocal, EnabledLocal);
					return __result;
				}
			}
			finally
			{
				if (HandleAddRef)
					Handle.DangerousRelease();
			}
		}

