			try
			{
				fixed (winmdroot.Foundation.BOOL* HasCapabilityLocal = &HasCapability)
				{
					winmdroot.Foundation.HANDLE TokenHandleLocal;
					if (TokenHandle is object)
					{
						TokenHandle.DangerousAddRef(ref TokenHandleAddRef);
						TokenHandleLocal = (winmdroot.Foundation.HANDLE)TokenHandle.DangerousGetHandle();
					}
					else
						TokenHandleLocal = (winmdroot.Foundation.HANDLE )new IntPtr(0L);
					winmdroot.Foundation.BOOL __result = PInvoke.CheckTokenCapability(TokenHandleLocal, CapabilitySidToCheck, HasCapabilityLocal);
					return __result;
				}
			}
			finally
			{
				if (TokenHandleAddRef)
					TokenHandle.DangerousRelease();
			}
